var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>국제연합군 신병훈련소</color> 지하 ███미터 지점 \\n<color=#ffd34c>퓨처 앳 워 계획</color> 중단 통보 ██시간 전","JPN":"<color=#ffd34c>国連軍新兵訓練所</color>地下███ｍ地点\\n<color=#ffd34c>フューチャーアットウォー計画</color> 中断通知██時間前","ENG":"<color=#ffd34c>International Coalition Forces bootcamp,</color> ███ meters underground \\n██ hours before the notification of <color=#ffd34c>Future-at-War</color> termination","TWN":"<color=#ffd34c>國際聯合軍隊新兵訓練所</color> 地下 ███公尺處 \\n<color=#ffd34c>天啟兵器計畫</color>終止通知 ██ 小時前","SCN":"<color=#ffd34c>国际联合军新兵训练所</color>地下███米地点\\n<color=#ffd34c>天启兵器计划</color>中断通报██小时前","DEU":"Keller als <color=#ffd34c>Neurekruten-Trainingslager für die Multinationalen Vereinten Streitkräfte</color>, etwa ███\xA0m weiter\\n██ Std. vor der Unterbrechung der Initiative von <color=#ffd34c>Future-at-War</color>","FRA":"<color=#ffd34c>Camp d'entraînement des Forces de la Coalition Internationale</color> ███ mètres sous le niveau du sol\\n██ heures avant l'avis d'arrêt du <color=#ffd34c>projet Future-at-War</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"시작형 전술통제용 강인공지능 <color=#ffd34c>호라이즌</color> – 대화 기록 중","JPN":"試作型戦術統制用強人工知能<color=#ffd34c>ホライズン</color> – 会話記録中","ENG":"Prototype strong A.I. for tactical control, <color=#ffd34c>HORIZON</color>. Activating system.","TWN":"開始型戰術控制強人工智慧<color=#ffd34c>地平線</color> – 記錄對話中","SCN":"战术控制用AI原型机<color=#ffd34c>地平线</color>——对话记录中","DEU":"Prototyp einer taktischen Steuerung mit allgemeiner KI, <color=#ffd34c>Horizon</color>. – Gespräch wird aufgezeichnet.","FRA":"Prototype d'intelligence artificielle générale de gestion tactique, <color=#ffd34c>HORIZON</color>. – Enregistrement en cours"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_NPC_PC_NULL","text":{"KOREA":"이 창고에 저를 처박아 뒀던 장본인에게 재가동되리라고는 예상 못했습니다.","JPN":"この倉庫に私をぶち込んだ張本人に再起動させられるとは思いも寄りませんでした。","ENG":"I had not anticipated the very same person who locked me up in this storage room would be the one reactivating me.","TWN":"沒想到，把我關在這裡的罪魁禍首，竟然會要求重新開機。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_NPC_PC_NULL","text":{"KOREA":"무슨 목적으로 제 앞에 다시 나타났습니까. 엠버 소장.","JPN":"何の目的で私の前に再び現れたのですか、アンバー所長。","ENG":"To what end have you come to me again, Director Ember?","TWN":"琥珀所長，請問你再次出現在我面前的目的是什麼？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"좋은 소식을 전해 주러 왔지. 들으면 깜짝 놀랄 거야.","JPN":"良い知らせがあるの。聞いたら驚くと思う。","ENG":"I come bearing good news. I'm sure you'll be delightfully surprised.","TWN":"來報好消息的，聽到會嚇一大跳喔。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"전쟁이 끝났어. 호라이즌. 우리 승리야.","JPN":"戦争が終わったんだ、ホライズン。我々の勝利だよ。","ENG":"The war is over, Horizon. We won!","TWN":"地平線，戰爭結束了，我們大獲全勝。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그렇습니까?","JPN":"そうですか。","ENG":"Is that so?","TWN":"是嗎？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"하나도 안 놀라네. 섭섭하게.","JPN":"全然驚いてくれないね、残念。","ENG":"You don't seem surprised at all. How disappointing.","TWN":"一點都不驚訝，真沒意思。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"전투용 인공지능은 전황에 동요하지 않아야 합니다. 당신이 그렇게 만들었죠.","JPN":"戦闘用人工知能はどんな戦況でも動揺してはいけません。そうさせたのはあなたです。","ENG":"Artificial intelligence for combat purposes are designed not to stir at the changing tides of battle. That is precisely how you designed me.","TWN":"戰鬥用人工智慧不能受戰況影響。這是你的設計。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그래서, 당신들의 자랑스러운 타이탄이 전쟁을 끝내기라도 했습니까?","JPN":"それで、あなたたちの誇り高いタイタンが戦争を終わらせたのですか？","ENG":"So did those Titans you humans are so proud of put an end to this war?","TWN":"所以是你們引以爲傲的泰坦結束戰爭的嗎？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"아니. 그라운드 원을 되찾았다는 소식이 전해졌을 때 우린 타이탄 양산 체제나 정비 중이었어.","JPN":"いや。グラウンド・ワンを取り戻したという知らせを聞いた時、私たちはまだタイタンの量産体制を準備していたんだ。","ENG":"No. We were just getting started on prepping serial production for Titan when we heard the news that they've reclaimed Ground One.","TWN":"不是。當我們得知收復G1的消息時，才在整理泰坦的量產系統而已。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"승리는 전부 안토노프 대령처럼 영웅적인 군인들의 희생 정신 덕분이지.","JPN":"勝利はすべて、アントノフ大佐のような勇ましい軍人たちの自己犠牲のおかげだね。","ENG":"This victory was all thanks to the heroic sacrifice of servicemembers like Colonel Antonov.","TWN":"這全都要歸功於，那群如安東諾夫上校般英勇的軍人，因為他們的犧牲精神才能取得勝利。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"네가 그 때 체르노프 교수님을 봤어야 했는데. 다 큰 아저씨가 어찌나 펑펑 울던지 원.","JPN":"あなたにもあの時のチェルノフ教授を見て欲しかったな。大の大人が号泣してたんだ。","ENG":"You should have seen Professor Chernov. I've never seen a full grown man cry so much.","TWN":"你都沒看到當時候的切爾諾夫教授，都那麼大的人還哭得跟什麼一樣。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EMBER_NPC_HORIZON_NULL","text":{"KOREA":"뭐, 일찌감치 전사한 장병들에게는……. 아무래도 좋을 이야기겠지만.","JPN":"まあ、とうに戦死した兵士たちには……どうでもいい話だけどね。","ENG":"Though I guess for those who already got killed in action… it doesn't really make a difference.","TWN":"不過，對那些很早就陣亡的士兵而言……這應該都算是個好消息吧？"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"제가 탑재된 고물 PC에 음주 측정 기능이 없어 유감이군요.","JPN":"私が搭載されたボロPCにアルコール検知機能がないのが残念ですね。","ENG":"It's regrettable that this antiquated desktop computer is not fitted with sensors for detecting blood alcohol content.","TWN":"很遺憾，我搭載的舊型電腦沒有酒測功能。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"하지만 두서 없는 대화만으로도 당신이 만취 상태라는 사실은 쉽게 추측할 수 있습니다.","JPN":"しかし、つじつまの合わない会話だけでも、あなたが泥酔状態ということは簡単に推測できます。","ENG":"But this ranting of yours is sufficient for me to deduce that you are thoroughly intoxicated.","TWN":"不過光是從你沒頭沒尾的談話看來，很容易就可以推測你應該是處於喝醉狀態。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"술주정은 변기에다 하십시오. 저는 당신의 감정 쓰레기통이 아닙니다.","JPN":"自分の悪い酒癖を自慢したいならトイレに行ってください。私はあなたの感情のはけ口ではありません。","ENG":"Such vulgar regurgitation is better suited for the porcelain toilet bowl. I am not your emotional trashcan.","TWN":"要發酒瘋請找馬桶，我不是你發洩情緒的垃圾桶。"},"stage":{"bg":"DATABASE_02","slots":{"L":null,"C":{"char_id":"EMBER_NPC_HORIZON_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};